"use strict";(self.webpackChunkdocumentation=self.webpackChunkdocumentation||[]).push([["2692"],{392499:function(e){e.exports=JSON.parse('{"version":{"pluginId":"adengine","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"adengine":[{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/","label":"Introduction","docId":"index","unlisted":false},{"type":"category","label":"How to","description":"How to use OptiView Ad Engine","collapsed":false,"customProps":{"icon":"\u{1F4D6}"},"items":[{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/how-to/ad-conformance","label":"Ad Conformance","docId":"how-to/ad-conformance","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/how-to/ad-delivery","label":"Ad Delivery","docId":"how-to/ad-delivery","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/how-to/ad-profile-creation","label":"Ad Profiles","docId":"how-to/ad-profile-creation","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/how-to/audio-assignment","label":"ABR Audio Assignment","docId":"how-to/audio-assignment","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/how-to/audio-normalization","label":"Audio Normalization","docId":"how-to/audio-normalization","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/how-to/quality-control","label":"Quality Control","docId":"how-to/quality-control","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/how-to/upconvert-to-vision-atmos","label":"Up-Converting Ads to Dolby Vision and Atmos","docId":"how-to/upconvert-to-vision-atmos","unlisted":false}],"collapsible":true},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/reference/dolby-optiview-ad-engine","label":"Introduction","docId":"reference/dolby-optiview-ad-engine","unlisted":false},{"type":"category","label":"Ad Engine","items":[{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/reference/create-ad-profile","label":"Create Ad Profile","className":"post api-method","docId":"reference/create-ad-profile","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/reference/modify-ad-profile","label":"Modify Ad Profile","className":"put api-method","docId":"reference/modify-ad-profile","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/reference/delete-ad-profile","label":"Delete Ad Profile","className":"delete api-method","docId":"reference/delete-ad-profile","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/reference/get-ad-profile","label":"Get Ad Profile","className":"get api-method","docId":"reference/get-ad-profile","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/reference/list-ad-profiles","label":"List Ad Profiles","className":"get api-method","docId":"reference/list-ad-profiles","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/reference/create-conformed-ad","label":"Create Conformed Ad","className":"get api-method","docId":"reference/create-conformed-ad","unlisted":false},{"type":"link","href":"/documentation/pr-preview/pr-453/ad-engine/reference/create-conformed-ad-pod","label":"Create Conformed Ad Pod","className":"post api-method","docId":"reference/create-conformed-ad-pod","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"how-to/ad-conformance":{"id":"how-to/ad-conformance","title":"Ad Conformance","description":"Ads are often sourced from master media files such as high bitrate MP4 or MOV files. But, sometimes the master media files is referenced in a VAST (Video Ad Serving Template) file. Or, the ad is actually already in an HLS format, but you need to convert it to a different bitrate ladder. On the output side, you may want to create a single MP4 file, or a multi-bitrate HLS file. Or you may want to create an HLS, but have that HLS be referenced in a VAST file. All of these different types of conformance can be executed by the OptiView Ad Engine:","sidebar":"adengine"},"how-to/ad-delivery":{"id":"how-to/ad-delivery","title":"Ad Delivery","description":"You have multiple ways that your ad can be delivered as part of the ad conformance process. The OptiView Ad Engine directly act as the origin, or you can have the Ad Engine place the finished files into your own origin (e.g. in your cloud or on your CDN).","sidebar":"adengine"},"how-to/ad-profile-creation":{"id":"how-to/ad-profile-creation","title":"Ad Profiles","description":"Before any ads can be processed by the OptiView Ad Engine, you must specify one or more ad profiles. The purpose of an ad profile is to define the parameters of your encoding, such as resolution, bitrate, etc. This is also where you define the audio normalization you desire and any quality control checks that should be performed.","sidebar":"adengine"},"how-to/audio-assignment":{"id":"how-to/audio-assignment","title":"ABR Audio Assignment","description":"You can create multiple audio bitrates in HLS, and then assign different bitrates to different video renditions. For example, on your 1080p high bitrate video you may have audio at 128kbps, whereas on your small 360p video you may only want audio at 64kbps. This allows you to minimize the combined video/audio bitrate for certain streams.","sidebar":"adengine"},"how-to/audio-normalization":{"id":"how-to/audio-normalization","title":"Audio Normalization","description":"An area of importance for ad processing is to have the ads match the source content in terms of audio volume. It will drive away viewers if your ads have wildly different volume than your primary content. Whether by accident or intent, ads are often set to very high volume. You can use the OptiView Ad Engine to normalize these ads so that all your ads are (1) consistent and (2) match your primary content.","sidebar":"adengine"},"how-to/quality-control":{"id":"how-to/quality-control","title":"Quality Control","description":"One of the realities of ads is that there are many instances where the ad source can be problematic. These types of problems can include things like too long duration, too short duration, too small dimensions, too low of a bitrate, etc. A bad ad can look bad, sound bad, or simple stall your player, so it is important to verify the quality of the ad.","sidebar":"adengine"},"how-to/upconvert-to-vision-atmos":{"id":"how-to/upconvert-to-vision-atmos","title":"Up-Converting Ads to Dolby Vision and Atmos","description":"The vast majority of ads are produced in SDR (Standard Dynamic Range) video and stereo audio. Many premium VOD and live assets are delivered, however, in Dolby Vision and Atmos. Dolby Vision is the leading HDR (High Dynamic Range) format and Dolby Atmos is the leading object-oriented audio format. You can optimize the viewing experience for your customers by up-converting the ad video and audio. Converting the ad video to Dolby Vision gives the ad more color depth and makes it look stunning. And most importantly, viewers are not switching back and forth between HDR primary content and SDR ads.","sidebar":"adengine"},"index":{"id":"index","title":"Dolby OptiView Ad Engine Introduction","description":"The OptiView Ad Engine is a just-in-time, serverless conformance service that transforms ads from their original master format into a streaming format that matches the primary content stream. This ensures smooth, consistent ad playback, improving the overall viewing experience and enhancing audience satisfaction. Because the Ad Engine operates just-in-time, it can prepare ads for playback within the span of an Early Ad Break Notification (EABN). The Ad Engine is compatible with any ad server, streaming engine, or player. Beyond transforming ads, it can also be used to integrate other types of content, such as editorial segments.","sidebar":"adengine"},"reference/create-ad-profile":{"id":"reference/create-ad-profile","title":"Create Ad Profile","description":"Create Ad Profile","sidebar":"adengine"},"reference/create-conformed-ad":{"id":"reference/create-conformed-ad","title":"Create Conformed Ad","description":"Create Conformed Ad","sidebar":"adengine"},"reference/create-conformed-ad-pod":{"id":"reference/create-conformed-ad-pod","title":"Create Conformed Ad Pod","description":"Create Conformed Ad Pod","sidebar":"adengine"},"reference/delete-ad-profile":{"id":"reference/delete-ad-profile","title":"Delete Ad Profile","description":"Delete Ad Profile","sidebar":"adengine"},"reference/dolby-optiview-ad-engine":{"id":"reference/dolby-optiview-ad-engine","title":"Dolby OptiView Ad Engine","description":"","sidebar":"adengine"},"reference/get-ad-profile":{"id":"reference/get-ad-profile","title":"Get Ad Profile","description":"Get Ad Profile","sidebar":"adengine"},"reference/list-ad-profiles":{"id":"reference/list-ad-profiles","title":"List Ad Profiles","description":"List Ad Profiles","sidebar":"adengine"},"reference/modify-ad-profile":{"id":"reference/modify-ad-profile","title":"Modify Ad Profile","description":"Modify Ad Profile","sidebar":"adengine"}}}}')}}]);